const body = $input.first().json.body || $input.first().json;

const requestId = 'ACC-' + Date.now();
const receivedAt = new Date().toISOString();

const inputType = body.visitorId ? 'visitor_signal' : 'company_input';

const visitorId = body.visitorId || '';
const ipAddress = body.ip || '';
const pagesVisited = Array.isArray(body.pagesVisited) ? body.pagesVisited : (body.pagesVisited ? [body.pagesVisited] : []);
const timeOnSite = body.timeOnSite || '0m 0s';
const visitsThisWeek = parseInt(body.visitsThisWeek) || 1;
const referralSource = body.referralSource || '';
const deviceType = body.deviceType || '';
const location = body.location || '';

const companyName = body.companyName || body.company || '';
const partialDomain = body.domain || '';

const intentPages = ['/pricing', '/demo', '/contact', '/checkout', '/trial', '/buy'];
const researchPages = ['/blog', '/resources', '/docs', '/documentation', '/learn'];
const productPages = ['/features', '/product', '/solutions', '/ai-sales-agent', '/case-studies'];

let pagePriorityScore = 0;
for (const page of pagesVisited) {
  if (intentPages.some(p => page.toLowerCase().includes(p))) pagePriorityScore += 3;
  else if (productPages.some(p => page.toLowerCase().includes(p))) pagePriorityScore += 2;
  else if (researchPages.some(p => page.toLowerCase().includes(p))) pagePriorityScore += 1;
}

const timeMatch = timeOnSite.match(/(\d+)m\s*(\d+)s/);
const timeSeconds = timeMatch ? (parseInt(timeMatch[1]) * 60 + parseInt(timeMatch[2])) : 0;

let rawIntentScore = 0;
rawIntentScore += Math.min(pagePriorityScore * 1.5, 4);
rawIntentScore += Math.min(visitsThisWeek * 0.8, 3);
rawIntentScore += timeSeconds > 180 ? 2 : timeSeconds > 60 ? 1 : 0;
rawIntentScore = Math.min(Math.round(rawIntentScore * 10) / 10, 9);

return [{
  json: {
    requestId,
    receivedAt,
    inputType,
    visitorId,
    ipAddress,
    pagesVisited,
    pagesVisitedStr: pagesVisited.join(', '),
    timeOnSite,
    visitsThisWeek,
    referralSource,
    deviceType,
    visitorLocation: location,
    companyName,
    partialDomain,
    rawIntentScore,
    pagePriorityScore
  }
}];

// Merge IP enrichment data with normalized input
const ipData = $input.first().json;
const normalizedData = $('Code - Normalize Input').first().json;

// Extract IP enrichment fields
const ipCity = ipData.city || '';
const ipRegion = ipData.region || '';
const ipCountry = ipData.country_name || '';
const ipOrg = ipData.org || '';
const ipTimezone = ipData.timezone || '';
const ipCurrency = ipData.currency || '';

// Build enriched location from IP if visitor didn't provide it
const enrichedLocation = normalizedData.visitorLocation || 
  [ipCity, ipRegion, ipCountry].filter(Boolean).join(', ');

// Try to infer company from IP org if no company name given
const inferredCompany = normalizedData.companyName || 
  (ipOrg ? ipOrg.replace(/^AS\d+\s+/i, '').trim() : '');

return [{
  json: {
    ...normalizedData,
    visitorLocation: enrichedLocation,
    companyName: inferredCompany,
    ipCity,
    ipRegion,
    ipCountry,
    ipOrg,
    ipTimezone,
    ipEnriched: !!(ipCity || ipCountry)
  }
}];

