const item = $input.first().json;
const normalizedData = $('Code - Merge IP Data').first().json;

let aiData = {};
try {
  const rawText = item.message?.content || item.choices?.[0]?.message?.content || '';
  const cleaned = rawText.replace(/```json/gi, '').replace(/```/g, '').trim();
  aiData = JSON.parse(cleaned);
} catch (e) {
  aiData = {
    companyName: normalizedData.companyName || 'Unknown',
    domain: normalizedData.partialDomain || '',
    industry: 'Unknown',
    companySize: 'Unknown',
    headquarters: normalizedData.visitorLocation || 'Unknown',
    foundingYear: 'Unknown',
    businessDescription: 'Could not enrich - AI parsing error.',
    likelyPersona: 'Unknown',
    personaConfidence: 0,
    intentScore: normalizedData.rawIntentScore,
    intentStage: 'Research',
    technologyStack: { crm: '', marketing: '', website: '', analytics: '' },
    businessSignals: [],
    keyDecisionMakers: [],
    aiSummary: 'AI enrichment failed. Manual research required.',
    recommendedActions: ['Manually research company', 'Verify visitor identity', 'Add to CRM for follow-up'],
    confidenceScore: 10
  };
}

// ============================================
// 1. KEY SIGNALS OBSERVED
// ============================================
const pages = normalizedData.pagesVisited || [];
const signals = [];

if (pages.some(p => p.includes('/pricing'))) signals.push('Visited pricing page');
if (pages.some(p => p.includes('/case-studies'))) signals.push('Viewed case studies');
if (pages.some(p => p.includes('/ai-sales-agent'))) signals.push('Viewed AI sales agent page');
if (pages.some(p => p.includes('/demo'))) signals.push('Requested demo page');
if (pages.some(p => p.includes('/features') || p.includes('/product'))) signals.push('Browsed product features');
if (pages.some(p => p.includes('/blog') || p.includes('/resources'))) signals.push('Read educational content');
if (normalizedData.visitsThisWeek > 1) signals.push('Repeat visits (' + normalizedData.visitsThisWeek + 'x this week)');
if (normalizedData.timeOnSite && normalizedData.timeOnSite !== '0m 0s') signals.push('High dwell time: ' + normalizedData.timeOnSite);
if (normalizedData.referralSource) signals.push('Referred from: ' + normalizedData.referralSource);
if (normalizedData.ipEnriched) signals.push('IP location verified: ' + normalizedData.ipCity + ', ' + normalizedData.ipCountry);

const keySignalsObserved = signals.join(' | ');

// ============================================
// 2. DATA CONFIDENCE SCORE
// ============================================
const aiConfidence = parseFloat(aiData.confidenceScore) || 0;

// Count how many key fields are actually filled
const fieldsToCheck = [
  aiData.companyName, aiData.domain, aiData.industry,
  aiData.companySize, aiData.headquarters, aiData.likelyPersona,
  aiData.businessDescription, aiData.aiSummary
];
const filledFields = fieldsToCheck.filter(f => f && f.trim() && f !== 'Unknown' && f !== '').length;
const dataCompletenessScore = Math.round((filledFields / fieldsToCheck.length) * 40); // max 40 pts

// IP enrichment bonus
const ipBonus = normalizedData.ipEnriched ? 15 : 0;

// Page signals bonus
const signalBonus = Math.min(signals.length * 3, 15); // max 15 pts

// AI raw confidence (scaled to 30)
const aiBonus = Math.round((aiConfidence / 100) * 30);

// Final confidence score out of 100
const finalConfidenceScore = Math.min(dataCompletenessScore + ipBonus + signalBonus + aiBonus, 100);

// ============================================
// 3. PRIORITY TIER
// ============================================
const intentScore = parseFloat(aiData.intentScore) || normalizedData.rawIntentScore;
let priorityTier = '';
if (intentScore >= 8) priorityTier = 'Priority 1 - Hot Lead';
else if (intentScore >= 6) priorityTier = 'Priority 2 - Warm Lead';
else if (intentScore >= 4) priorityTier = 'Priority 3 - Nurture';
else priorityTier = 'Priority 4 - Cold';

// ============================================
// BUILD OUTPUT FIELDS
// ============================================
const tech = aiData.technologyStack || {};
const techSummary = Object.entries(tech)
  .filter(([_, v]) => v && v.trim())
  .map(([k, v]) => k + ': ' + v)
  .join(' | ');

const dmSummary = (aiData.keyDecisionMakers || [])
  .map(dm => dm.role + (dm.name && dm.name !== 'Unknown' ? ': ' + dm.name : ''))
  .join(', ');

const actionsStr = (aiData.recommendedActions || []).join(' | ');
const signalsStr = (aiData.businessSignals || []).join(', ');

return [{
  json: {
    requestId: normalizedData.requestId,
    receivedAt: normalizedData.receivedAt,
    inputType: normalizedData.inputType,
    visitorId: normalizedData.visitorId,
    ipAddress: normalizedData.ipAddress,
    pagesVisited: normalizedData.pagesVisitedStr,
    timeOnSite: normalizedData.timeOnSite,
    visitsThisWeek: normalizedData.visitsThisWeek,
    // Company Profile
    companyName: aiData.companyName || normalizedData.companyName,
    domain: aiData.domain || normalizedData.partialDomain,
    industry: aiData.industry,
    companySize: aiData.companySize,
    headquarters: aiData.headquarters,
    foundingYear: aiData.foundingYear,
    businessDescription: aiData.businessDescription,
    // Persona & Intent
    likelyPersona: aiData.likelyPersona,
    personaConfidence: aiData.personaConfidence + '%',
    intentScore: intentScore + ' / 10',
    intentStage: aiData.intentStage,
    priorityTier,
    // Enrichment
    technologyStack: techSummary,
    businessSignals: signalsStr,
    keyDecisionMakers: dmSummary,
    // NEW: Key Signals Observed
    keySignalsObserved,
    // NEW: Data Confidence Score
    confidenceScore: finalConfidenceScore + '%',
    confidenceBreakdown: 'Data: ' + dataCompletenessScore + ' | IP: ' + ipBonus + ' | Signals: ' + signalBonus + ' | AI: ' + aiBonus,
    // Summary & Actions
    aiSummary: aiData.aiSummary,
    recommendedActions: actionsStr,
    rawActions: aiData.recommendedActions || [],
    rawDecisionMakers: aiData.keyDecisionMakers || []
  }
}];
